import{_ as e,o,c as a,a2 as d}from"./chunks/framework.OWFDNrRT.js";const p=JSON.parse('{"title":"Compatibility Matrix","description":"DINOForge version compatibility with game, BepInEx, and Unity versions","frontmatter":{"title":"Compatibility Matrix","description":"DINOForge version compatibility with game, BepInEx, and Unity versions"},"headers":[],"relativePath":"compat.md","filePath":"compat.md","lastUpdated":1773460793000}'),r={name:"compat.md"};function i(n,t,s,l,c,h){return o(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="compatibility-matrix" tabindex="-1">Compatibility Matrix <a class="header-anchor" href="#compatibility-matrix" aria-label="Permalink to &quot;Compatibility Matrix&quot;">​</a></h1><p>DINOForge uses a 6-tier status ladder to communicate version compatibility. This page helps you determine if your DINOForge version works with your DINO game installation.</p><h2 id="status-ladder" tabindex="-1">Status Ladder <a class="header-anchor" href="#status-ladder" aria-label="Permalink to &quot;Status Ladder&quot;">​</a></h2><p>The following statuses indicate compatibility levels and recommended actions:</p><table tabindex="0"><thead><tr><th>Status</th><th>Color</th><th>Description</th><th>Installer Action</th></tr></thead><tbody><tr><td><strong>Optimal</strong></td><td>Green (#22c55e)</td><td>Fully tested and verified. All features work. Recommended configuration.</td><td>Proceed</td></tr><tr><td><strong>Stable</strong></td><td>Lime (#84cc16)</td><td>Works reliably. Minor edge cases possible. Community tested.</td><td>Proceed</td></tr><tr><td><strong>Maintenance</strong></td><td>Yellow (#eab308)</td><td>Functional but receiving security fixes only. Upgrade recommended.</td><td>Warn</td></tr><tr><td><strong>Unstable</strong></td><td>Orange (#f97316)</td><td>Known issues. Partial functionality. Use at own risk.</td><td>Warn Strongly</td></tr><tr><td><strong>Broken</strong></td><td>Red (#ef4444)</td><td>Known incompatible. Will not function correctly.</td><td>Block</td></tr><tr><td><strong>Unknown</strong></td><td>Gray (#6b7280)</td><td>Untested combination. No compatibility data available.</td><td>Warn</td></tr></tbody></table><h2 id="compatibility-matrix-1" tabindex="-1">Compatibility Matrix <a class="header-anchor" href="#compatibility-matrix-1" aria-label="Permalink to &quot;Compatibility Matrix&quot;">​</a></h2><h3 id="current-releases" tabindex="-1">Current Releases <a class="header-anchor" href="#current-releases" aria-label="Permalink to &quot;Current Releases&quot;">​</a></h3><table tabindex="0"><thead><tr><th>DINOForge</th><th>DINO Game</th><th>BepInEx</th><th>Unity</th><th>Status</th><th>Notes</th></tr></thead><tbody><tr><td>0.5.x</td><td><code>&gt;=1.0.0</code></td><td><code>&gt;=5.4.21</code> <code>&amp;lt;6.0.0</code></td><td>2021.3.*</td><td><strong>Optimal</strong></td><td>Current stable release. Fully tested.</td></tr><tr><td>0.4.x</td><td><code>&gt;=1.0.0</code></td><td><code>&gt;=5.4.21</code> <code>&amp;lt;6.0.0</code></td><td>2021.3.*</td><td><strong>Maintenance</strong></td><td>Security fixes only. Upgrade to 0.5.x recommended.</td></tr><tr><td>0.3.x</td><td><code>&gt;=1.0.0</code></td><td><code>&gt;=5.4.21</code> <code>&amp;lt;6.0.0</code></td><td>2021.3.*</td><td><strong>Broken</strong></td><td>No longer supported. Upgrade to 0.5.x required.</td></tr></tbody></table><h3 id="experimental-future" tabindex="-1">Experimental / Future <a class="header-anchor" href="#experimental-future" aria-label="Permalink to &quot;Experimental / Future&quot;">​</a></h3><table tabindex="0"><thead><tr><th>DINOForge</th><th>DINO Game</th><th>BepInEx</th><th>Unity</th><th>Status</th><th>Notes</th></tr></thead><tbody><tr><td>0.5.x</td><td><code>&gt;=1.0.0</code></td><td><code>&gt;=6.0.0</code></td><td>2021.3.*</td><td><strong>Unknown</strong></td><td>BepInEx 6.x (Mono) support planned for DINOForge 1.0. Not yet tested.</td></tr><tr><td>0.5.x</td><td><code>&gt;=2.0.0</code></td><td><code>&gt;=5.4.21</code> <code>&amp;lt;6.0.0</code></td><td>2022.*</td><td><strong>Unknown</strong></td><td>Future DINO game version. No compatibility data available yet.</td></tr></tbody></table><h2 id="component-compatibility" tabindex="-1">Component Compatibility <a class="header-anchor" href="#component-compatibility" aria-label="Permalink to &quot;Component Compatibility&quot;">​</a></h2><p>ECS component layouts may change between game versions. The following components have been tested:</p><table tabindex="0"><thead><tr><th>Component</th><th>Field</th><th>DINO Versions</th><th>Status</th><th>Notes</th></tr></thead><tbody><tr><td><code>Components.Health</code></td><td><code>currentHealth</code></td><td><code>&gt;=1.0</code></td><td><strong>Optimal</strong></td><td>Confirmed via entity dump. Core health tracking for units and buildings.</td></tr><tr><td><code>Components.HealthBase</code></td><td><code>_maxHealthMultiplier</code></td><td><code>&gt;=1.0</code></td><td><strong>Stable</strong></td><td>Private field, may change in patches. Max health multiplier mutable value.</td></tr><tr><td><code>Components.Unit</code></td><td>(tag)</td><td><code>&gt;=1.0</code></td><td><strong>Optimal</strong></td><td>Zero-sized tag marking entities as units. Verified present on all units.</td></tr><tr><td><code>Components.ArmorData</code></td><td><code>type</code></td><td><code>&gt;=1.0</code></td><td><strong>Optimal</strong></td><td>ArmorType enum. Confirmed layout stable across patches.</td></tr><tr><td><code>Components.AttackCooldown</code></td><td><code>value</code></td><td><code>&gt;=1.0</code></td><td><strong>Stable</strong></td><td>Cooldown timer. Also carries fixedProjectileSpeed field.</td></tr><tr><td><code>Components.ProjectileDataBase</code></td><td>(blob ref)</td><td><code>&gt;=1.0</code></td><td><strong>Optimal</strong></td><td><code>BlobAssetReference&lt;ProjectileData&gt;</code>. Immutable, verified on projectile entities.</td></tr><tr><td><code>Components.BuildingBase</code></td><td>(core)</td><td><code>&gt;=1.0</code></td><td><strong>Optimal</strong></td><td>Present on all buildings. Core building data container.</td></tr><tr><td><code>Components.Enemy</code></td><td>(faction marker)</td><td><code>&gt;=1.0</code></td><td><strong>Stable</strong></td><td>Enemy faction marker (<code>BlobAssetReference&lt;EnemyBaseData&gt;</code>). Player units lack this tag.</td></tr></tbody></table><h2 id="upgrading-between-versions" tabindex="-1">Upgrading Between Versions <a class="header-anchor" href="#upgrading-between-versions" aria-label="Permalink to &quot;Upgrading Between Versions&quot;">​</a></h2><h3 id="_0-3-x-→-0-5-x" tabindex="-1">0.3.x → 0.5.x <a class="header-anchor" href="#_0-3-x-→-0-5-x" aria-label="Permalink to &quot;0.3.x → 0.5.x&quot;">​</a></h3><p>0.3.x is no longer supported and incompatible with 0.5.x. A full reinstall is required:</p><ol><li>Remove all 0.3.x mod packs from <code>BepInEx/plugins/</code></li><li>Update DINOForge Runtime plugin to 0.5.x</li><li>Reinstall mod packs targeting 0.5.x</li></ol><h3 id="_0-4-x-→-0-5-x" tabindex="-1">0.4.x → 0.5.x <a class="header-anchor" href="#_0-4-x-→-0-5-x" aria-label="Permalink to &quot;0.4.x → 0.5.x&quot;">​</a></h3><p>0.4.x packs should be compatible with 0.5.x, but it is recommended to update when the pack author publishes a 0.5.x version.</p><h2 id="important-notes" tabindex="-1">Important Notes <a class="header-anchor" href="#important-notes" aria-label="Permalink to &quot;Important Notes&quot;">​</a></h2><ul><li><strong>DINO Game Version</strong>: The game uses Unity 2021.3.45f2. Game updates may change ECS component layouts without warning.</li><li><strong>BepInEx 6.x</strong>: Full support planned for DINOForge 1.0. Currently using BepInEx 5.4.23.5.</li><li><strong>Mono Runtime</strong>: DINO uses the Mono runtime (not IL2CPP), which is important for BepInEx compatibility.</li></ul><h2 id="reporting-compatibility-issues" tabindex="-1">Reporting Compatibility Issues <a class="header-anchor" href="#reporting-compatibility-issues" aria-label="Permalink to &quot;Reporting Compatibility Issues&quot;">​</a></h2><p>If you encounter incompatibility issues not listed here, please report them on the <a href="https://github.com/KooshaPari/Dino/issues" target="_blank" rel="noreferrer">GitHub Issues</a> page.</p><h2 id="machine-readable-data" tabindex="-1">Machine-Readable Data <a class="header-anchor" href="#machine-readable-data" aria-label="Permalink to &quot;Machine-Readable Data&quot;">​</a></h2><p>For programmatic access to compatibility data, see the <a href="/Dino/compat.json">compat.json</a> file.</p>',25)])])}const u=e(r,[["render",i]]);export{p as __pageData,u as default};
